int numWays(vector<string> &words, string target) {
    int n = words[0].size();
    int m = target.size();
    vector<vector<int>> cnt(n, vector<int>(26, 0));
    for(auto word : words) {
        for(int i = 0 ; i < word.size() ; i++) {
            cnt[i][word[i]-'a']++;
        }
    }
    int mod = 1e9+7;
    vector<vector<int>> dp(n+1, vector<int>(m+1, 0));
    for(int i = 0 ; i <= n ; i++) dp[i][0] = 1;

    for(int i = 1 ; i <= n ; i++) {
        for(int j = 1 ; j <= m ; j++) {
            dp[i][j] = dp[i-1][j];          // don't choose the character from ith place

            char ch = target[j-1];
            if(cnt[i-1][ch-'a'] > 0) {        // if there is a character present at ith place then choose it
                dp[i][j] += (dp[i-1][j-1] * cnt[i-1][ch-'a']);
            }
            dp[i][j] %= mod;
        }
    }
    return dp[n][m];
}

// DP Solution for Q2 in C++ 
// Time: Quadratic complexity
// Space: Linear

int filteringMessages(string messageA, string messageB, string virusC) {

       // Trivial Case 1
	if (messageA > messageB) {
		return 0;
	}

	// Trivial Case 2
	if (messageA == messageB) {
		return messageA.find(virusC) == -1;
	}

	// Storing virus and message size
	int messageSize = messageA.size();
	int virusSize = virusC.size();

	// dp[i] = count of strings of length i and 
	// lie between prefix of length i in messageA
	// and prefix of length i in messageB 
	// (not inclusive of prefixs);
	// and does not have virusC as substring
	// that is dp[i] = 
	// COUNT((string of length i) such that: prefix(messageA of length i) < 
	// (string of length i) < prefix(message) and ((string of length i))
	// does not contain virusC as substring)

	// NOTE: symbols are < and >; and not <= and >=.

	vector<int> dp(messageSize + 1);
	int idx = 0, mod = 1e9 + 7;

	// ignoring trivial cases, and this simplies our solution
	while (messageA[idx] == messageB[idx]) {
		idx++;
	}

	// starting with first non-matching prefixes of messageA and messageB
	int len = idx + 1;
	for (int i = len; i <= messageSize; i++) {
		if (i == len) {
			dp[i] = messageB[i - 1] - messageA[i - 1] - 1;
		} else {
			dp[i] = 1ll * dp[i - 1] * 26 % mod;
			if (messageA.substr(0, i - 1).find(virusC) == -1) {
				dp[i] += 'z' - messageA[i - 1];
				dp[i] %= mod;
			}
			if (messageB.substr(0, i - 1).find(virusC) == -1) {
				dp[i] += messageB[i - 1] - 'a';
				dp[i] %= mod;
			}
		}

		if (i == virusSize) {
			string curr_beg = messageA.substr(0, i);
			string curr_end = messageB.substr(0, i);
			if (curr_beg < virusC and virusC < curr_end) {
				dp[i] = (0ll + dp[i] - 1 + mod) % mod;
			}  
		} else if (i > virusSize) {
			dp[i] = (0ll + dp[i] - dp[i - virusSize] + mod) % mod;

			// handling corner equlity cases seperately.
			string curr_beg = messageA.substr(0, i);
			string curr_end = messageB.substr(0, i);
			string beg = messageA.substr(0, i - virusSize) + virusC;
			string end = messageB.substr(0, i - virusSize) + virusC;
			if (curr_beg < beg and beg < curr_end) {
				dp[i] = (0ll + dp[i] - 1 + mod) % mod;
			}  
			if (curr_beg < end and end < curr_end) {
				dp[i] = (0ll + dp[i] - 1 + mod) % mod;
			} 
		}
	}

	// calculating answer by adding dp[messageSize] and 2 equality cases
	int ans = dp[messageSize] + (messageA.find(virusC) == -1) + (messageB.find(virusC) == -1);
	ans %= mod;

	return ans;
}

