def traversal(input, r_index, t_index, match_string, result, build_string):
    for i in range(len(input)):
        for j in range(r_index, len(input[i])):
            if match_string == build_string + input[i][j]:
                result.append(1)
            traversal(input, j+1, t_index+1, match_string, result, build_string+input[i][j])
