def uber_oa2(a, b, virus):
    count = 0
    m = a
    def add_one(msg):
        carry = 1
        i = len(msg) - 1
        msg = list(msg) # converting back and forth between a list and str is not ideal, could be improved by leaving as a list and using Rabin-Karp for virus substring search condition below
        while carry:
            if chr(ord(msg[i]) + 1) > 'z':
                msg[i] = 'a'
                carry = 1
                i -= 1
            else:
                msg[i] = chr(ord(msg[i]) + 1)
                carry = 0
        return ''.join(msg)
    while True:
        m = add_one(m)
        if virus not in m:
            count += 1
        if not m <= b or m == a:
            break 
    return count % ((10 ** 9) + 7)
