def uber_oa1(words, target):
    chars = []
    for word in words:
        for i,ch in enumerate(word):
            chars.append((i,ch))
    chars.sort()
    count = 0
    def backtrack(chars_start, target_i, prev_index):
        nonlocal count
        if target_i == len(target):
            count += 1
            return 
        for i in range(chars_start,len(chars)):
            if chars[i][1] == target[target_i] and chars[i][0] > prev_index:
                backtrack(i+1, target_i+1, chars[i][0])
    backtrack(0,0,-1)
    return count % ((10 ** 9) + 7)

